const a = [
  {"id":6629,"text":"At the end of the plateau of the cardiac action potential, the influx of calcium ions to the interior of the muscle fibers is suddenly cut off, and the calcium ions in the sarcoplasm are rapidly pumped back out of the muscle fibers into both the sarcoplasmic reticulum (SR) and the T-tubule extracellular fluid space. Transport of Ca⁺² back into the SR occurs via:","explanation":null,"reference":null,"responses":[{"text":"Sodium-calcium exchanger","correct":false,"visible":false},{"text":"Ca-ATPase pump","correct":true,"visible":false},{"text":"Dihydropyridine receptor","correct":false,"visible":false},{"text":"Na-K ATPase pump","correct":false,"visible":false},{"text":"Ryanodine receptor channels","correct":false,"visible":false}]},{"id":7554,"text":"The hepatic oxidation of cholesterol mainly leads to the synthesis of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Atheromatous matrix","correct":false,"visible":false},{"text":"Intermediary steroids","correct":false,"visible":false},{"text":"Bile acids","correct":true,"visible":false},{"text":"Coprostanol","correct":false,"visible":false},{"text":"Reproductive hormones","correct":false,"visible":false}]},{"id":7663,"text":"Chylomicrons are transformed into chylomicron remnants by the hydrolysis of the core triglycerides through the action of which enzyme?","explanation":null,"reference":null,"responses":[{"text":"Lipoprotein lipase","correct":true,"visible":false},{"text":"Chylomicron transferase","correct":false,"visible":false},{"text":"Cholesteryl esterase","correct":false,"visible":false},{"text":"Apolipoprotein synthase","correct":false,"visible":false},{"text":"Cholesteryl transferase","correct":false,"visible":false}]},{"id":7670,"text":"Consumption of which class of dietary fatty acids substantially relates with the lowering of the risk of developing heart disease?","explanation":null,"reference":"Ferrier, Denise R. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Lippincott Illustrated Reviews. Philadelphia: Wolters Kluwer, 2020: 363.","responses":[{"text":"Saturated fatty acids","correct":false,"visible":false},{"text":"Unsaturated fatty acids","correct":false,"visible":false},{"text":"Monounsaturated fatty acids","correct":false,"visible":false},{"text":"Polyunsaturated fatty acids","correct":true,"visible":false},{"text":"Medium saturated fatty acids","correct":false,"visible":false}]},{"id":7680,"text":"What does the communication strategy in crisis intervention known as \"paraphrasing\" entail?","explanation":null,"reference":null,"responses":[{"text":"Asking questions to clarify a person's statement","correct":false,"visible":false},{"text":"Using non-verbal communication such as maintaining eye contact, head nodding, etc","correct":false,"visible":false},{"text":"Conveying empathy and understanding by repeating portions of what the person said","correct":false,"visible":false},{"text":"Helping the person identify and articulate emotions","correct":false,"visible":false},{"text":"Summarizing multiple elements of a person's message/statement","correct":true,"visible":false}]},{"id":7682,"text":"Which lipoprotein particle has anti-oxidant, anti-inflammatory, and anti-apoptotic properties and contributes to inhibiting atherosclerosis?","explanation":null,"reference":null,"responses":[{"text":"Intermediate density lipoproteins","correct":false,"visible":false},{"text":"High density lipoproteins","correct":true,"visible":false},{"text":"Chylomicron remnants","correct":false,"visible":false},{"text":"Chylomicrons","correct":false,"visible":false},{"text":"Low density lipoproteins","correct":false,"visible":false}]},{"id":7693,"text":"The smallest lipoprotein particles of high-density lipoprotein cholesterol (HDL-C) are densest due to which of the following reasons?","explanation":null,"reference":null,"responses":[{"text":"Minimal proportion of phosphate and highest proportion of lipids","correct":false,"visible":false},{"text":"Highest proportion of proteins to lipids","correct":true,"visible":false},{"text":"Lowest proportion of proteins to lipids","correct":false,"visible":false},{"text":"Highest proportion of phosphate and minimal proportion of lipids","correct":false,"visible":false},{"text":"Moderate proportion of proteins and highest proportion of lipids","correct":false,"visible":false}]},{"id":7695,"text":"What is the blood pressure response to sodium chloride termed as?","explanation":null,"reference":null,"responses":[{"text":"Salt sensitivity","correct":true,"visible":false},{"text":"Salt specificity","correct":false,"visible":false},{"text":"Ion-counter pathway","correct":false,"visible":false},{"text":"Ion sensitivity","correct":false,"visible":false},{"text":"Ion specificity","correct":false,"visible":false}]},{"id":7703,"text":"The hydrolysis of triglycerides from VLDL by muscle and adipose tissue results in the formation of which pro-atherogenic, cholesterol-enriched particles?","explanation":null,"reference":null,"responses":[{"text":"Low density lipoproteins","correct":false,"visible":false},{"text":"Chylomicrons","correct":false,"visible":false},{"text":"Intermediate density lipoproteins","correct":true,"visible":false},{"text":"High density lipoproteins","correct":false,"visible":false},{"text":"Chylomicron remnants","correct":false,"visible":false}]},{"id":7893,"text":"A first-year resident is studying the valvular outlet of the ventricle and is positioned at the infundibulum. This is present at which valve?","explanation":null,"reference":null,"responses":[{"text":"Right atrioventricular","correct":false,"visible":false},{"text":"Aortic","correct":false,"visible":false},{"text":"Pulmonary","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Left atrioventricular","correct":false,"visible":false}]},{"id":7922,"text":"Which part of the conduction pathway has the slowest conduction rate?","explanation":null,"reference":null,"responses":[{"text":"AV node","correct":true,"visible":false},{"text":"Purkinje fibres","correct":false,"visible":false},{"text":"Right bundle branch","correct":false,"visible":false},{"text":"SA node","correct":false,"visible":false},{"text":"lnternodal pathway","correct":false,"visible":false}]},{"id":8108,"text":"Ventricular depolarization and repolarization is shown by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Q-T interval","correct":true,"visible":false},{"text":"T wave","correct":false,"visible":false},{"text":"QRS complex","correct":false,"visible":false},{"text":"P wave","correct":false,"visible":false},{"text":"P-R interval","correct":false,"visible":false}]},{"id":8113,"text":"Which part of the heart causes a delay in impulse transmission?","explanation":null,"reference":null,"responses":[{"text":"Sinoatrial node","correct":false,"visible":false},{"text":"Inter nodal fibers","correct":false,"visible":false},{"text":"Atrioventricular node","correct":true,"visible":false},{"text":"Purkinje fibers","correct":false,"visible":false},{"text":"Bundle branches","correct":false,"visible":false}]},{"id":8151,"text":"Dextrocardia is commonly associated with which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"Tetralogy of Fallot","correct":false,"visible":false},{"text":"Situs inversus","correct":true,"visible":false},{"text":"Aortic stenosis","correct":false,"visible":false},{"text":"Coarctation of aorta","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":false,"visible":false}]},{"id":8261,"text":"Which of the following is involved in generating the pumping force of the heart?","explanation":null,"reference":null,"responses":[{"text":"Myocardium","correct":true,"visible":false},{"text":"Papillary muscles","correct":false,"visible":false},{"text":"Endothelium","correct":false,"visible":false},{"text":"Epicardium","correct":false,"visible":false},{"text":"Endocardium","correct":false,"visible":false}]},{"id":8687,"text":"What are the main stages of crisis intervention?","explanation":null,"reference":null,"responses":[{"text":"Agreement only","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Assessment, exploration, and agreement","correct":true,"visible":false},{"text":"Assessment only","correct":false,"visible":false},{"text":"Exploration only","correct":false,"visible":false}]},{"id":9360,"text":"Which of the following is the rate-limiting enzyme in cholesterol synthesis?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 221.","responses":[{"text":"HMG-CoA synthase","correct":false,"visible":false},{"text":"Mevalonate carboxylase","correct":false,"visible":false},{"text":"HMG-CoA reductase","correct":true,"visible":false},{"text":"Prenyl transferase","correct":false,"visible":false},{"text":"Squalene synthase","correct":false,"visible":false}]},{"id":10096,"text":"Lungs are supplied by pulmonary and bronchial vessels. Which of the following blood vessels carries poorly oxygenated blood from the heart to the lungs?","explanation":"The heart pumps blood to various parts of the body through a network of blood vessels. The lungs, vital for the process of oxygenation of blood, receive blood supply through both the pulmonary and bronchial vessels. The **pulmonary arteries** are responsible for carrying poorly oxygenated blood from the right ventricle of the heart to the lungs. This deoxygenated blood travels via the pulmonary arteries into the pulmonary capillaries where it gets oxygenated. Following oxygenation, the blood returns to the left atrium of the heart via the pulmonary veins, now rich in oxygen. On the other hand, bronchial arteries provide oxygenated blood to the lung tissue itself, branching off the aorta. It's crucial to understand that it's somewhat counterintuitive: in the systemic circulation, arteries carry oxygenated blood, but in the pulmonary circulation, arteries carry deoxygenated blood to be oxygenated in the lungs.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 170.","responses":[{"text":"Bronchial veins","correct":false,"visible":false},{"text":"Pulmonary veins","correct":false,"visible":false},{"text":"Bronchial arteries","correct":false,"visible":false},{"text":"Pulmonary capillaries","correct":false,"visible":false},{"text":"Pulmonary arteries","correct":true,"visible":false}]},{"id":12164,"text":"Perforations in septum primum coalesce before the closure of foramen primum. This leads to the formation of which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 294.","responses":[{"text":"Septum secundum","correct":false,"visible":false},{"text":"Foramen secondum","correct":true,"visible":false},{"text":"Sinus venosus","correct":false,"visible":false},{"text":"Coronary sinus","correct":false,"visible":false},{"text":"Foramen ovale","correct":false,"visible":false}]},{"id":12168,"text":"A smooth part in the right atrium, which is a remnant of the right sinus horn is seen by some medical students while dissecting a cadaver. The part can be identified as which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 299.","responses":[{"text":"Crista terminalis","correct":false,"visible":false},{"text":"Sinus venarum","correct":true,"visible":false},{"text":"Coronary sinus","correct":false,"visible":false},{"text":"Fossa ovalis","correct":false,"visible":false},{"text":"Right ventricle","correct":false,"visible":false}]},{"id":12178,"text":"From which of the following aortic arches does ductus arteriosus arise?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 208.","responses":[{"text":"3rd aortic arch","correct":false,"visible":false},{"text":"Left 4th aortic arch","correct":false,"visible":false},{"text":"Left 6th aortic arch","correct":true,"visible":false},{"text":"1st aortic arch","correct":false,"visible":false},{"text":"Right 6th aortic arch","correct":false,"visible":false}]},{"id":12210,"text":"Which of the following events in the cardiac cycle produces the first heart sound?","explanation":null,"reference":"Costanzo LS. Physiology. 6th ed. Elsevier; 2018: 157.","responses":[{"text":"Relaxation of the ventricles","correct":false,"visible":false},{"text":"Closure of the AV valves","correct":true,"visible":false},{"text":"Contraction of atria","correct":false,"visible":false},{"text":"Opening of the AV valves","correct":false,"visible":false},{"text":"Closure of the aortic valve","correct":false,"visible":false}]},{"id":12369,"text":"Regarding fetal circulation of the heart, which of the following events will occur immediately after birth?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 219.","responses":[{"text":"Formation of ligamentum venosum","correct":false,"visible":false},{"text":"Closure of ductus arteriosus","correct":true,"visible":false},{"text":"Closure of ductus venosus","correct":false,"visible":false},{"text":"Obliteration of left umbilical vein","correct":false,"visible":false},{"text":"Closure of foramen ovale","correct":false,"visible":false}]},{"id":12393,"text":"Persistent hiccups can be caused by the irritation of which of the following nerves?","explanation":null,"reference":"Quiroga JB, García JU, Guedes JB. Hiccups: a common problem with some unusual causes and cures. The British Journal of General Practice. Published November 2016. Accessed November 9, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5072913/","responses":[{"text":"Vagus nerve","correct":false,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false},{"text":"Phrenic nerve","correct":false,"visible":false},{"text":"Recurrent laryngeal nerve","correct":false,"visible":false},{"text":"Both vagus and phrenic nerves","correct":true,"visible":false}]},{"id":12811,"text":"Which of the following is the point of formation of the superior vena cava?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 220.","responses":[{"text":"Left third costal cartilage","correct":false,"visible":false},{"text":"Left first costal cartilage","correct":false,"visible":false},{"text":"Left second costal cartilage","correct":false,"visible":false},{"text":"Right third costal cartilage","correct":false,"visible":false},{"text":"Right first costal cartilage","correct":true,"visible":false}]},{"id":12820,"text":"A patient presents to the cardiology outpatient department with difficulty breathing after walking a short distance. After examination and investigation, a diagnosis of stenosis of the aortic valve is made. In which of the following costal cartilages, is the narrowed valve located?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 364.","responses":[{"text":"Right first costal cartilage","correct":false,"visible":false},{"text":"Left first costal cartilage","correct":false,"visible":false},{"text":"Left second costal cartilage","correct":false,"visible":false},{"text":"Right third costal cartilage","correct":false,"visible":false},{"text":"Left third costal cartilage","correct":true,"visible":false}]},{"id":12821,"text":"A 50-year-old man presents to the emergency department with a complaint of chest pain for the past hour. An electrocardiogram (ECG) of the patient suggests a complete block of the right and left bundle of His. Which one of the following arteries is occluded in the patient?","explanation":null,"reference":"Moore KL, Dalley AF, Agur AMR. Clinically Oriented Anatomy. 7th ed. Wolters Kluwer/Lippincott Williams \u0026 Wilkins Health; 2014: 147.","responses":[{"text":"Main diagonal branch","correct":false,"visible":false},{"text":"Anterior interventricular artery","correct":true,"visible":false},{"text":"Circumflex artery","correct":false,"visible":false},{"text":"Left marginal artery","correct":false,"visible":false},{"text":"Right marginal artery","correct":false,"visible":false}]},{"id":12822,"text":"During cardiac surgery, the surgeon passes his finger through a potential space, that separates the great arteries from the atria and the veins. Which of the following potential spaces is it?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 188.","responses":[{"text":"Oblique pericardial sinus","correct":false,"visible":false},{"text":"Anterior costomediastinal recess","correct":false,"visible":false},{"text":"Transverse pericardial sinus","correct":true,"visible":false},{"text":"Costodiaphragmatic recess","correct":false,"visible":false},{"text":"Superior aortic recess","correct":false,"visible":false}]},{"id":12823,"text":"Which of the following arteries is responsible for the myocardial infarction of the inferior wall of the myocardium?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 145.","responses":[{"text":"Right coronary artery","correct":true,"visible":false},{"text":"Anterior interventricular artery","correct":false,"visible":false},{"text":"Left coronary artery","correct":false,"visible":false},{"text":"Posterior interventricular artery","correct":false,"visible":false},{"text":"Right marginal artery","correct":false,"visible":false}]},{"id":12824,"text":"Vasa vasorum are predominantly found in the large arteries and veins. Which of the following best describes vasa vasorum?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 220.","responses":[{"text":"Blood vessels within the wall of blood vessels","correct":true,"visible":false},{"text":"Blood vessels of the myocardium","correct":false,"visible":false},{"text":"Nerves that supply the blood vessels","correct":false,"visible":false},{"text":"Blood vessels of the endocardium","correct":false,"visible":false},{"text":"Nerves of the endocardium","correct":false,"visible":false}]},{"id":12825,"text":"The microscopic structure of the tunica media consists of concentric layers of smooth muscle fibers with variable amounts of reticular and elastic fibers in between. Which of the following vessels contains the largest percentage of elastic fibers in their tunica media?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 220.","responses":[{"text":"Jugular vein","correct":false,"visible":false},{"text":"Inferior vena cava","correct":false,"visible":false},{"text":"Coronary artery","correct":false,"visible":false},{"text":"Aorta","correct":true,"visible":false},{"text":"Medium sized artery","correct":false,"visible":false}]},{"id":12827,"text":"Prenatally, the ductus arteriosus shunts blood from the pulmonary trunk to the descending aorta. By what time is it closed postnatally in full-term infants?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 327.","responses":[{"text":"96 hours","correct":false,"visible":false},{"text":"72 hours","correct":false,"visible":false},{"text":"48 hours","correct":true,"visible":false},{"text":"24 hours","correct":false,"visible":false},{"text":"12 hours","correct":false,"visible":false}]},{"id":12829,"text":"Which of the following congenital defects is marked by the incomplete fusion of the endocardial tissue?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 197, 198.","responses":[{"text":"Transposition of great vessels","correct":false,"visible":false},{"text":"Atrioventricular septal defect","correct":true,"visible":false},{"text":"Tetralogy of fallot","correct":false,"visible":false},{"text":"Coarctation of aorta","correct":false,"visible":false},{"text":"Pulmonary stenosis","correct":false,"visible":false}]},{"id":12830,"text":"The fetal cardiovascular system is designed to serve prenatal needs and permit modifications at birth that establish the neonatal circulatory pattern. Which of the following events is included in the transition from fetal to neonatal circulation?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 325-326.","responses":[{"text":"Closure of foramen ovale","correct":true,"visible":false},{"text":"Vasodilation of umbilical arteries","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":false,"visible":false},{"text":"Thicker walls of the ventricles","correct":false,"visible":false},{"text":"Dilatation of the ductus venous sphincter","correct":false,"visible":false}]},{"id":12831,"text":"Which of the following phenomena occurs during ventricular systole?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 119.","responses":[{"text":"Atrioventricular valves are closed","correct":true,"visible":false},{"text":"Intra-atrial pressure is greater than intra-ventricular pressure","correct":false,"visible":false},{"text":"Blood is forced through atrioventricular valves","correct":false,"visible":false},{"text":"Mitral valve is open","correct":false,"visible":false},{"text":"Atria are contracting","correct":false,"visible":false}]},{"id":12837,"text":"Which of the following formulae corresponds to cardiac output?","explanation":null,"reference":"(1) Costanzo LS. BRS: Physiology. 7th ed. Wolters Kluwer; 2019: 85. (2) King J, Lowery DR. Physiology, cardiac output. StatPearls. Published 2022. Accessed December 4, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470455/","responses":[{"text":"End-diastolic volume - End-systolic volume","correct":false,"visible":false},{"text":"Heart rate x Stroke volume","correct":true,"visible":false},{"text":"Heart rate / Ejection fraction","correct":false,"visible":false},{"text":"(End-diastolic volume - Stroke volume) x Heart rate","correct":false,"visible":false},{"text":"Heart rate / Stroke volume","correct":false,"visible":false}]},{"id":12841,"text":"Which of the following reasons accounts for a thicker left ventricular wall as compared to the right ventricular wall?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 195.","responses":[{"text":"To pump blood through a smaller valve","correct":false,"visible":false},{"text":"To pump a greater volume of blood","correct":false,"visible":false},{"text":"To accommodate a greater volume of blood","correct":false,"visible":false},{"text":"To pump blood with greater pressure","correct":true,"visible":false},{"text":"To expand the thoracic cage during diastole","correct":false,"visible":false}]},{"id":12844,"text":"Given an end-diastolic volume of 150 ml, an end-systolic volume of 50 ml, and a heart rate of 60 beats per minute, what will be the cardiac output?","explanation":null,"reference":"Costanzo LS. Physiology. 6th ed. Elsevier; 2018: 149, 150.","responses":[{"text":"600 mL/minute","correct":false,"visible":false},{"text":"15 L/minute","correct":false,"visible":false},{"text":"6 L/minute","correct":true,"visible":false},{"text":"60000 mL/minute","correct":false,"visible":false},{"text":"3 L/minute","correct":false,"visible":false}]},{"id":12845,"text":"Which of the following is the only electrical connection between the atria and the ventricles?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 147.","responses":[{"text":"Atrioventricular node","correct":true,"visible":false},{"text":"Atrioventricular delay","correct":false,"visible":false},{"text":"Atrioventricular valve","correct":false,"visible":false},{"text":"Bundle branches","correct":false,"visible":false},{"text":"Bundle of His","correct":false,"visible":false}]},{"id":12857,"text":"Due to which of the following properties of cardiac muscle fibers, the cardiac contractile muscles do not exhibit tetanus?","explanation":null,"reference":"Dow lecture slides. Cardiovascular Module-I; Subject: Physiology, Topic: Properties of cardiac muscles.","responses":[{"text":"They have long absolute refractory period","correct":true,"visible":false},{"text":"They exclusively undergo aerobic respiration","correct":false,"visible":false},{"text":"They exclusively undergo anaerobic respiration","correct":false,"visible":false},{"text":"They have well-developed sarcoplasmic reticulum","correct":false,"visible":false},{"text":"They are slow oxidative muscle fibres","correct":false,"visible":false}]},{"id":12860,"text":"A diabetic patient presents to the emergency department with a heart rate of 32 beats per minute and a blood sugar level of more than 500mg/dL. A drug ''atropine'' is prescribed to increase the heart rate. What is this effect called?","explanation":null,"reference":"Costanzo LS. Physiology. 6th ed. Elsevier; 2018: 141.","responses":[{"text":"Positive chronotropic effect","correct":true,"visible":false},{"text":"Positive inotropic effect","correct":false,"visible":false},{"text":"Negative chronotropic effect","correct":false,"visible":false},{"text":"Negative inotropic effect","correct":false,"visible":false},{"text":"Negative dromotropic effect","correct":false,"visible":false}]},{"id":12865,"text":"Which of the following substances is most likely to cause a rapid drop in blood pressure?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 300.","responses":[{"text":"Angiotensin II","correct":false,"visible":false},{"text":"Histamine","correct":true,"visible":false},{"text":"Thromboxane A2","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Nicotine","correct":false,"visible":false}]},{"id":12889,"text":"What will be the mean arterial pressure of a person having a systolic blood pressure of 130 mmHg and a diastolic blood pressure of 70 mmHg?","explanation":null,"reference":"Costanzo LS. Physiology. 6th ed. Elsevier; 2018: 129, 130.","responses":[{"text":"80 mmHg","correct":false,"visible":false},{"text":"95 mmHg","correct":false,"visible":false},{"text":"75 mmHg","correct":false,"visible":false},{"text":"90 mmHg","correct":true,"visible":false},{"text":"100 mmHg","correct":false,"visible":false}]},{"id":12896,"text":"Which of the following would cause a decrease in stroke volume, compared with the normal resting value?","explanation":null,"reference":"Costanzo LS. Physiology. 6th ed. Elsevier; 2018: 158.","responses":[{"text":"Increase in venous return","correct":false,"visible":false},{"text":"Reduction in afterload","correct":false,"visible":false},{"text":"Increase heart rate \u003e 200/minute","correct":true,"visible":false},{"text":"Increase in end-diastolic volume","correct":false,"visible":false},{"text":"Sympathetic stimulation of the heart","correct":false,"visible":false}]},{"id":12901,"text":"Vagal stimulation results in the slowing of the heart rate. This is due to the increased permeability of the sinoatrial nodal fiber membrane to which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 125.","responses":[{"text":"Sodium and calcium","correct":false,"visible":false},{"text":"Potassium","correct":true,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Chloride","correct":false,"visible":false},{"text":"Sodium","correct":false,"visible":false}]},{"id":12916,"text":"A 50-year-old man was brought to the emergency department when he suddenly developed an acute right-sided chest pain that started radiating to the right arm. An electrocardiogram (ECG) of the patient showed an ST-segment elevation. This segment corresponds to which phase of the cardiac contraction potential?","explanation":null,"reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 115. (2) Kashou AH, Basit H, Malik A. St segment. StatPearls. Published 2022. Accessed December 5, 2022. http://www.ncbi.nlm.nih.gov/books/NBK459364/","responses":[{"text":"Phase 2","correct":true,"visible":false},{"text":"Phase 0","correct":false,"visible":false},{"text":"Phase 1","correct":false,"visible":false},{"text":"Phase 4","correct":false,"visible":false},{"text":"Phase 3","correct":false,"visible":false}]},{"id":12917,"text":"Which of the following circuits represents the lowest resistance pathway?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 177.","responses":[{"text":"Cerebral circulation","correct":false,"visible":false},{"text":"Coronary circulation","correct":false,"visible":false},{"text":"Hepatic circulation","correct":false,"visible":false},{"text":"Renal circulation","correct":false,"visible":false},{"text":"Pulmonary circulation","correct":true,"visible":false}]},{"id":12920,"text":"A 55-year-old man presents to the emergency room with a complaint of sudden chest pain. His electrocardiogram reveals an ST-segment elevation in leads II, III, and avF. Laboratory investigation of his blood sample for the presence of cardiac enzymes shows raised levels of troponin T and a diagnosis of myocardial infarction is made. Which of the following walls of the myocardium is infarcted?","explanation":null,"reference":"Warner MJ, Tivakaran VS. Inferior myocardial infarction. StatPearls. Published 2022. Accessed December 5, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470572/","responses":[{"text":"Anterior","correct":false,"visible":false},{"text":"Lateral","correct":false,"visible":false},{"text":"Inferior","correct":true,"visible":false},{"text":"Posterior","correct":false,"visible":false},{"text":"Anterolateral","correct":false,"visible":false}]},{"id":12922,"text":"A 48-year-old man presents to the emergency department with a complaint of chest pain for the past 4-5 hours. He is profusely sweating and also has slight dyspnea. Which of the following is expected to be elevated?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 547.\r\n(2) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 65.","responses":[{"text":"Pyruvate kinase","correct":false,"visible":false},{"text":"Hexokinase","correct":false,"visible":false},{"text":"Alkaline phosphatase","correct":false,"visible":false},{"text":"Creatine kinase-MB","correct":true,"visible":false},{"text":"Lactate dehydrogenase","correct":false,"visible":false}]},{"id":12941,"text":"Which of the following lipoproteins has the least percentage of protein?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 227.","responses":[{"text":"Very low density lipoprotein","correct":false,"visible":false},{"text":"Intermediate density lipoprotein","correct":false,"visible":false},{"text":"Chylomicron","correct":true,"visible":false},{"text":"Low density lipoprotein","correct":false,"visible":false},{"text":"High density lipoprotein","correct":false,"visible":false}]},{"id":12942,"text":"Which of the following hormones increases the endogenous synthesis of cholesterol?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 241.","responses":[{"text":"Estrogen","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Insulin","correct":true,"visible":false},{"text":"Glucocorticoids","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false}]},{"id":12943,"text":"A 50-year-old woman is diagnosed with familial LCAT (lecithin-cholesterol acyltransferase) deficiency after a renal biopsy. She has a marked decrease in esterified cholesterol and low levels of high-density lipoproteins (HDL), as well as decreased activity of LCAT. Which of the following is a principal activator of LCAT?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 234.","responses":[{"text":"Apolipoprotein A-1","correct":true,"visible":false},{"text":"Apolipoprotein C-2","correct":false,"visible":false},{"text":"Apolipoprotein B","correct":false,"visible":false},{"text":"Apolipoprotein E","correct":false,"visible":false},{"text":"Apolipoprotein B-48","correct":false,"visible":false}]},{"id":12949,"text":"Foam cells and fatty streaks are primarily induced by unchecked phagocytosis of LDL-c (low-density lipoprotein) particles in the vascular subendothelium. Which dietary supplement may inhibit this mechanism?","explanation":null,"reference":"(1) Chatterjea, M. N., and Rana Shinde. Textbook of Medical Biochemistry. 8th ed. New Delhi: Jaypee Brothers Medical Publications, 2012: 172.\r\n(2) Huang ZG, Liang C, Han SF, Wu ZG. Vitamin E ameliorates ox-LDL-induced foam cells formation through modulating the activities of oxidative stress-induced NF-κB pathway. Molecular and Cellular Biochemistry. Published April 2012. https://pubmed.ncbi.nlm.nih.gov/22139346/","responses":[{"text":"Vitamin B12","correct":false,"visible":false},{"text":"Vitamin E","correct":true,"visible":false},{"text":"Vitamin K","correct":false,"visible":false},{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin B6","correct":false,"visible":false}]},{"id":12950,"text":"Hypertriglyceridemia that presents with xanthomas is most likely caused by the deficiency of which of the following molecules?","explanation":null,"reference":"(1) Le T, Bhushan V, Qiu C, et al., eds. First Aid for the USMLE Step 1 2023. 33rd ed. McGraw Hill; 2023: 92. (2) Yuan G, Al-Shali KZ, Hegele RA. Hypertriglyceridemia: its etiology, effects and treatment. CMAJ : Canadian Medical Association Journal. Published April 10, 2007. Accessed December 5, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC1839776/","responses":[{"text":"Apolipoprotein C","correct":false,"visible":false},{"text":"HMG CoA reductase","correct":false,"visible":false},{"text":"HMG CoA synthase","correct":false,"visible":false},{"text":"Apolipoprotein B","correct":false,"visible":false},{"text":"Lipoprotein lipase","correct":true,"visible":false}]},{"id":12952,"text":"Which of the following is mainly responsible for the regulation of plasma sodium?","explanation":null,"reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 375. (2) Ackerman GL, Walker HK, Hall WD, Hurst JW. Serum sodium. Clinical Methods: The History, Physical, and Laboratory Examinations. Published 1990. Accessed December 5, 2022. http://www.ncbi.nlm.nih.gov/books/NBK306/","responses":[{"text":"Urinary excretion","correct":false,"visible":false},{"text":"Sweating","correct":false,"visible":false},{"text":"Blood flow","correct":false,"visible":false},{"text":"Defecation","correct":false,"visible":false},{"text":"Thirst","correct":true,"visible":false}]},{"id":12954,"text":"A 56-year-old man was brought to the emergency department by his office colleagues with complaints of severe crushing chest pain associated with dyspnea and sweating for the past hour. He was immediately given a vasodilator but the pain did not subside. If the patient's condition does not improve and prolongs for more than 40 minutes, which of the following conditions can develop?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 550.","responses":[{"text":"Atrial fibrillation","correct":false,"visible":false},{"text":"Sudden cardiac death","correct":false,"visible":false},{"text":"Myocardial infarction","correct":true,"visible":false},{"text":"Coronary artery syndrome","correct":false,"visible":false},{"text":"Arrhythmia","correct":false,"visible":false}]},{"id":12967,"text":"A 48-year-old man experienced deep localized chest pain associated with dyspnea and sweating which was relieved with rest. According to him, the pain developed after a long tiring day at his job. Pain in this condition is induced due to the release of which of the following mediators?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 268.","responses":[{"text":"Epinephrine","correct":false,"visible":false},{"text":"Interleukins","correct":false,"visible":false},{"text":"Adenosine","correct":false,"visible":false},{"text":"Serotonin","correct":false,"visible":false},{"text":"Histamine","correct":true,"visible":false}]},{"id":12968,"text":"A 75-year-old male died due to complications of malignant hypertension. A biopsy of the kidney was done. Which of the following histological findings may be found in this case?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 493.","responses":[{"text":"Onion-skin concentric thickening","correct":true,"visible":false},{"text":"Atherosclerosis","correct":false,"visible":false},{"text":"Glomerular scarring","correct":false,"visible":false},{"text":"Widening of lumen","correct":false,"visible":false},{"text":"Hyaline thickening of arterioles","correct":false,"visible":false}]},{"id":12994,"text":"A 58-year-old man presents to the outpatient department with a complaint of reduced exercise tolerance over the past five years. In the past year, he has noticed chest pain after climbing stairs. He smokes two packs of cigarettes per day. On examination, he has a blood pressure of 155/95 mmHg. Laboratory investigations include total serum cholesterol of 245 mg/dL, with high-density lipoprotein cholesterol of 22 mg/dL. Which of the following vascular abnormalities is most likely to have developed in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 498.","responses":[{"text":"Cardiac hypertrophy","correct":false,"visible":false},{"text":"Medial calcific sclerosis","correct":false,"visible":false},{"text":"Atherosclerosis","correct":true,"visible":false},{"text":"Hyperplastic arteriosclerosis","correct":false,"visible":false},{"text":"Deep venous thrombosis","correct":false,"visible":false}]},{"id":12995,"text":"An atrial septal defect is one of the most common congenital heart diseases. Which of the following structures is involved in this defect?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 537.","responses":[{"text":"Truncus arteriosus","correct":false,"visible":false},{"text":"Ductus arteriosus","correct":false,"visible":false},{"text":"Ductus venosus","correct":false,"visible":false},{"text":"Septum secundum","correct":true,"visible":false},{"text":"Septum primum","correct":false,"visible":false}]},{"id":12996,"text":"Which of the following terms describes the impairment of heart function due to inadequate blood flow caused by obstructive changes in the coronary circulation to the heart?","explanation":null,"reference":"Dow lecture slides. Cardiovascular module-I; Subject: Community Medicine, Topic: Cardiovascular Diseases, Sub-topic: What are cardiovascular diseases?","responses":[{"text":"Cerebrovascular disease","correct":false,"visible":false},{"text":"Congenital heart disease","correct":false,"visible":false},{"text":"Rheumatic heart disease","correct":false,"visible":false},{"text":"Coronary heart disease","correct":true,"visible":false},{"text":"Congestive heart failure","correct":false,"visible":false}]},{"id":12997,"text":"In healthy individuals, physical activity reduces the risk of cardiovascular disease mortality by 20-30%. What are the current guidelines regarding the frequency of physical activity?","explanation":null,"reference":"(1)  Dow lecture slides. Cardiovascular module-I; Subject: Community Medicine, Topic: Lifestyle in Prevention of Cardiovascular Diseases. (2) https://www.cdc.gov/physicalactivity/basics/adults/index.htm","responses":[{"text":"Twenty minutes of moderate exercise five days a week","correct":false,"visible":false},{"text":"Sixty minutes of moderate exercise five days a week","correct":false,"visible":false},{"text":"Thirty minutes of moderate exercise five days a week","correct":true,"visible":false},{"text":"Sixty minutes of vigorous exercise five days a week","correct":false,"visible":false},{"text":"Thirty minutes of vigorous exercise five days a week","correct":false,"visible":false}]},{"id":12998,"text":"Conflict resolution is the process of ending a dispute and reaching an agreement that satisfies all parties involved. Since conflict is an essential part of being human, effective conflict resolution is not designed to avoid disagreements. Instead, conflict resolution skills are used to facilitate discussions, increase understanding, and control emotional responses. Which of the following does not pertain to the most cognitive errors that lead to unproductive and unresolved conflicts?","explanation":null,"reference":"Overton AR, Lowry AC. Conflict management: difficult conversations with difficult people. Clinics in Colon and Rectal Surgery. Published December 2013. Accessed December 9, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3835442/","responses":[{"text":"Emotional volatility","correct":false,"visible":false},{"text":"Overconfidence","correct":false,"visible":false},{"text":"Blaming","correct":false,"visible":false},{"text":"Self-serving fairness interpretation","correct":false,"visible":false},{"text":"Emotional regulation","correct":true,"visible":false}]},{"id":12999,"text":"Japan is a part of the Pacific Ring of Fire, the most active earthquake belt in the world, and accounts for 20% of earthquakes worldwide. Because of this, the government of Japan has designed buildings in a way that reduces loss as a result of an earthquake. Advanced precautionary measures have reduced the death toll and damage as a result of an earthquake. Which of these best explains the timely precautionary measures made by the government of Japan?","explanation":null,"reference":"Dow lecture slides. Cardiovascular module-I; Subject: Behavioral Sciences, Topic: Crisis Intervention.","responses":[{"text":"Coping skills","correct":false,"visible":false},{"text":"Post-traumatic growth","correct":false,"visible":false},{"text":"Post-traumatic stress disorder","correct":false,"visible":false},{"text":"Crisis intervention","correct":true,"visible":false},{"text":"Resolution of crisis","correct":false,"visible":false}]},{"id":13000,"text":"An 18-year-old male presents to the outpatient clinic with complaints of palpitations for the last two hours and frequent episodes of joint pain for four years. He has a blood pressure of 110/60 mmHg and a regular pulse of 120 beats per minute. On examination, a mild systolic murmur is heard in the apical area. Which of the following investigations should be advised to the patient?","explanation":null,"reference":"(1) Dow lecture slides. Cardiovascular module-I; Subject: Cardiology, Topic: Cardiac Imaging. (2) CDC. Valvular Heart Disease | cdc.gov. Centers for Disease Control and Prevention. Published December 9, 2019. Accessed January 27, 2023. https://www.cdc.gov/heartdisease/valvular_disease.htm","responses":[{"text":"Trans-thoracic echocardiography (TTE)","correct":true,"visible":false},{"text":"Exercise tolerance test","correct":false,"visible":false},{"text":"Nuclear imaging","correct":false,"visible":false},{"text":"Coronary angiography","correct":false,"visible":false},{"text":"Dobutamine stress echocardiography","correct":false,"visible":false}]},{"id":13001,"text":"A 45-year-old woman presents to the outpatient department with a complaint of typical chest pain radiating to her left arm associated with vomiting for the past three hours. She has a habit of smoking. Her vitals show a blood pressure of 130/70 mmHg and a regular pulse of 130 beats per minute. The systemic examination is remarkable. Her electrocardiogram(ECG) showed an ST-segment elevation in inferior ECG leads. What would be the most appropriate test for this patient?","explanation":"The most appropriate test for this 45-year-old woman presenting with typical chest pain, vomiting, and ST-segment elevation in inferior ECG leads is **coronary angiography**. Given the clinical presentation and ECG changes, she is likely experiencing an **ST-elevation myocardial infarction (STEMI)**. Immediate coronary angiography is the gold standard for both diagnosis and potentially immediate treatment via percutaneous coronary intervention (PCI).\r\n\r\nExercise tolerance test, dobutamine stress echocardiography, nuclear imaging, and trans-thoracic echocardiography are not appropriate for the acute management of a patient with a likely STEMI. These tests are generally used for assessing chronic coronary artery disease or for risk stratification but are not suitable for immediate diagnosis and treatment in the setting of acute chest pain with ST-segment elevation.","reference":"de Bliek EC. ST elevation: Differential diagnosis and caveats. A comprehensive review to help distinguish ST elevation myocardial infarction from nonischemic etiologies of ST elevation. Turkish Journal of Emergency Medicine. Published February 17, 2018. Accessed December 9, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6009807/","responses":[{"text":"Nuclear imaging","correct":false,"visible":false},{"text":"Coronary angiography","correct":true,"visible":false},{"text":"Exercise tolerance test","correct":false,"visible":false},{"text":"Trans-thoracic echocardiography","correct":false,"visible":false},{"text":"Dobutamine stress echocardiography","correct":false,"visible":false}]},{"id":13002,"text":"A young man undergoing a pre-recruitment check-up is suspected of cardiomegaly on examination. Which of the following is the most appropriate and cost-effective radiological investigation for determining the size of the heart and the chamber responsible for the enlargement?","explanation":null,"reference":"Hota P, Simpson S. Going beyond cardiomegaly: evaluation of cardiac chamber enlargement at non–electrocardiographically gated multidetector ct: current techniques, limitations, and clinical implications. Radiology: Cardiothoracic Imaging. Published April 25, 2019. Accessed December 6, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7977935/","responses":[{"text":"Chest X-ray (Posteroanterior view)","correct":false,"visible":false},{"text":"Nuclear scan","correct":false,"visible":false},{"text":"Contrast enhanced computerized tomography scan","correct":true,"visible":false},{"text":"Cardiac Magnetic Resonance Imaging (MRI)","correct":false,"visible":false},{"text":"Doppler echocardiography","correct":false,"visible":false}]},{"id":15501,"text":"Which of the following structures opens into the left atrium?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 363.","responses":[{"text":"Coronary sinus","correct":false,"visible":false},{"text":"Superior vena cava","correct":false,"visible":false},{"text":"Pulmonary veins","correct":true,"visible":false},{"text":"Aorta","correct":false,"visible":false},{"text":"Inferior vena cava","correct":false,"visible":false}]},{"id":15502,"text":"Which one of the following vessels is mainly responsible for controlling the local blood flow to the organs according to their needs?","explanation":null,"reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 173.","responses":[{"text":"Veins","correct":false,"visible":false},{"text":"Capillaries","correct":false,"visible":false},{"text":"Venules","correct":false,"visible":false},{"text":"Arterioles","correct":true,"visible":false},{"text":"Artery","correct":false,"visible":false}]},{"id":15503,"text":"Which of the following provides the nerve supply to the left ventricle?","explanation":null,"reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 130.","responses":[{"text":"Left bundle branch","correct":true,"visible":false},{"text":"Right bundle branch","correct":false,"visible":false},{"text":"Posterior nodal fibers","correct":false,"visible":false},{"text":"Anterior nodal fibers","correct":false,"visible":false},{"text":"Bundle of His","correct":false,"visible":false}]},{"id":15504,"text":"What is the most common type of lipid present in atheroma plaque?","explanation":null,"reference":"Sattar, Husain A. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com, 2021: 68.","responses":[{"text":"Intermediate density lipoprotein","correct":false,"visible":false},{"text":"Apo-lipoprotein","correct":false,"visible":false},{"text":"Low density lipoprotein","correct":false,"visible":false},{"text":"High density lipoprotein","correct":false,"visible":false},{"text":"Cholestrol","correct":true,"visible":false}]},{"id":15505,"text":"Which of the following effects results from the excitation of baroreceptors in arteries?","explanation":"Excitation of baroreceptors in arteries leads to **decreased arterial pressure**. Baroreceptors, located primarily in the carotid sinuses and aortic arch, are sensitive to changes in arterial pressure. When arterial pressure rises, baroreceptors are stimulated and send signals to the cardiovascular center in the brainstem. This results in a reflexive decrease in cardiac output and peripheral vasodilation through parasympathetic activation and sympathetic inhibition. This response, known as the baroreceptor reflex, is a key mechanism in maintaining blood pressure homeostasis. The other options, such as increased cardiac output, prolonged PR interval, peripheral vasoconstriction, and vasovagal syncope, are not direct results of baroreceptor excitation. Vasovagal syncope is a complex response involving baroreceptors but typically occurs under different circumstances, such as emotional stress or prolonged standing.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 7.","responses":[{"text":"Decreased arterial pressure","correct":true,"visible":false},{"text":"Peripheral vasoconstriction","correct":false,"visible":false},{"text":"Vasovagal syncope","correct":false,"visible":false},{"text":"Prolonged PR interval","correct":false,"visible":false},{"text":"Increased cardiac output","correct":false,"visible":false}]},{"id":15506,"text":"Which of the following lipoproteins is anti-atherogenic?","explanation":"**High density lipoprotein (HDL)** is considered anti-atherogenic. HDL plays a crucial role in reverse cholesterol transport, a process where cholesterol is transported from the peripheral tissues back to the liver for excretion. This action helps in reducing the buildup of cholesterol in arterial walls, thereby lowering the risk of atherosclerosis. Unlike other lipoproteins like low density lipoprotein (LDL), very low density lipoprotein (VLDL), chylomicrons, and intermediate density lipoprotein (IDL), which are involved in the transport of cholesterol and triglycerides to the peripheral tissues and can contribute to plaque formation, HDL is unique in its protective cardiovascular role. Its ability to remove cholesterol from atherosclerotic plaques is a key factor in its anti-atherogenic property.","reference":"Dow lecture slides. Cardiovascular module-I; Subject: Biochemistry, Topic: Synthesis of HDL.","responses":[{"text":"Very low density lipoprotein","correct":false,"visible":false},{"text":"High density lipoprotein","correct":true,"visible":false},{"text":"Low density lipoprotein","correct":false,"visible":false},{"text":"Intermediate density lipoprotein","correct":false,"visible":false},{"text":"Chylomicron","correct":false,"visible":false}]},{"id":15507,"text":"Which of the following causes vasodilation of the cerebral arteries?","explanation":"**Hydrogen ions** cause vasodilation of the cerebral arteries. In the cerebral circulation, an increase in hydrogen ion concentration (i.e., a decrease in pH) leads to vasodilation. This is a crucial mechanism to ensure increased blood flow to areas of the brain that are metabolically active and producing more carbon dioxide, which subsequently forms carbonic acid and dissociates into hydrogen ions. This increased blood flow helps in removing metabolic waste and supplying oxygen and nutrients. Lactic acid, which can accumulate in tissues under anaerobic conditions, also contributes to vasodilation, but its primary effect is mediated through the production of hydrogen ions. Adenosine, a metabolic byproduct, can cause vasodilation, but its role is more prominent in cardiac and skeletal muscle. Oxygen, conversely, causes vasoconstriction in cerebral vessels; decreased oxygen levels would promote vasodilation. Hydroxide ions do not directly cause vasodilation in cerebral arteries.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 777.","responses":[{"text":"Oxygen","correct":false,"visible":false},{"text":"Lactic acid","correct":false,"visible":false},{"text":"Adenosine","correct":false,"visible":false},{"text":"Hydroxide ions","correct":false,"visible":false},{"text":"Hydrogen ions","correct":true,"visible":false}]},{"id":15508,"text":"Which of the following blood vessels is the most prone to atherosclerosis?","explanation":"The **anterior wall of the abdominal aorta** is the most prone to atherosclerosis. Atherosclerosis preferentially affects the abdominal aorta, particularly its anterior wall. This area is subject to significant hemodynamic stress due to its large caliber and high blood flow, which promotes the development of atherosclerotic plaques. The abdominal aorta's susceptibility is further increased by factors like systemic hypertension and the presence of circulating atherogenic lipids.","reference":"Sattar, Husain A. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com, 2019: 68.","responses":[{"text":"At the point of bifurcation of arteries","correct":false,"visible":false},{"text":"Radial artery","correct":false,"visible":false},{"text":"Hepatic arteries","correct":false,"visible":false},{"text":"Renal arteries","correct":false,"visible":false},{"text":"Anterior wall of abdominal aorta","correct":true,"visible":false}]},{"id":15509,"text":"A 50-year-old smoker develops chest pain while doing an activity. What is the most important modifiable factor to reduce the risk of myocardial infarction?","explanation":"The most important modifiable factor to reduce the risk of myocardial infarction in this scenario is **smoking**. Smoking is a well-established major risk factor for coronary artery disease, which leads to myocardial infarction. It contributes to the development of atherosclerosis and increases the risk of thrombosis, both of which are key pathological mechanisms in myocardial infarction. While factors like physical inactivity can also contribute to cardiovascular risk, the impact of smoking cessation on reducing the risk of myocardial infarction is more significant. Race, gender, and age are non-modifiable factors and cannot be changed to reduce risk. Therefore, cessation of smoking is the most impactful change this individual can make to decrease their risk of myocardial infarction.","reference":"Kumar, Vinay, Abul K. Abbas, and Jon C. Aster. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Philadelphia, PA: Elsevier Saunders, 2015: 492.","responses":[{"text":"Gender","correct":false,"visible":false},{"text":"Physical inactivity","correct":false,"visible":false},{"text":"Age","correct":false,"visible":false},{"text":"Race","correct":false,"visible":false},{"text":"Smoking","correct":true,"visible":false}]},{"id":15510,"text":"What is the most abundant component of tunica media of the aorta?","explanation":"The most abundant component of the tunica media of the aorta is **elastin**. The aorta, being a large elastic artery, has a tunica media rich in elastin to accommodate the high pressure and volume of blood ejected from the heart. This elasticity allows the aorta to expand and recoil, helping to maintain blood pressure and continuous blood flow during the cardiac cycle. While smooth muscles, collagen, and reticular fibers are also present in the tunica media, their proportion is significantly less compared to elastin. Cholesterol is not a structural component of the arterial wall but can accumulate in the arteries in pathological conditions like atherosclerosis.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 220.","responses":[{"text":"Cholesterol","correct":false,"visible":false},{"text":"Smooth muscles","correct":false,"visible":false},{"text":"Collagen","correct":false,"visible":false},{"text":"Elastin","correct":true,"visible":false},{"text":"Reticular fibers","correct":false,"visible":false}]},{"id":15546,"text":"Which of the following structures forms the right border of the heart in a normal chest radiograph PA view?","explanation":"In a normal chest radiograph, particularly the posteroanterior (PA) view, the **right atrium** forms the right border of the heart. The right atrium, being the most anteriorly and rightward positioned chamber, is responsible for creating the silhouette seen on the right side of the heart in this imaging modality. The left atrium is positioned posteriorly and does not contribute to the borders in a PA view. Similarly, the right ventricle, being located more anteriorly and centrally, is not typically visible as part of the right heart border in a PA chest radiograph. The right pulmonary artery and the pulmonary trunk, although important structures in the mediastinum, do not contribute to the outer contour of the heart as seen in this specific view.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 193.","responses":[{"text":"Right ventricle","correct":false,"visible":false},{"text":"Left atrium","correct":false,"visible":false},{"text":"Right atrium","correct":true,"visible":false},{"text":"Pulmonary trunk","correct":false,"visible":false},{"text":"Right pulmonary artery","correct":false,"visible":false}]},{"id":15554,"text":"Where does the ductus arteriosus arise from?","explanation":"The **ductus arteriosus** arises from the **left sixth aortic arch**. During fetal development, the ductus arteriosus is a vital structure that connects the pulmonary artery to the descending aorta, allowing blood to bypass the non-functioning fetal lungs. The right sixth aortic arch typically regresses and does not contribute to the formation of the ductus arteriosus. The fourth aortic arches give rise to different structures: the left fourth arch forms part of the aortic arch, while the right fourth arch contributes to the formation of the right subclavian artery.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 320.","responses":[{"text":"Left fourth aortic arch","correct":false,"visible":false},{"text":"Left sixth aortic arch","correct":true,"visible":false},{"text":"Right sixth aortic arch","correct":false,"visible":false},{"text":"Left and right fourth aortic arches","correct":false,"visible":false},{"text":"Left and right sixth aortic arches","correct":false,"visible":false}]},{"id":15555,"text":"A patient comes to the emergency department 4-5 hours after a myocardial infarction. Which of the following cardiac markers will be detected at this point?","explanation":"In a patient presenting 4-5 hours after a myocardial infarction (MI), the cardiac marker most likely to be detected is **Troponin I**. Troponin I is considered the most sensitive and specific marker for myocardial injury. Troponin I levels begin to rise 2-4 hours after the onset of MI, peak at around 24 hours, and can remain elevated for 7-10 days. This time frame makes troponin I an ideal marker for early detection of MI, including in the 4-5 hour post-infarction window you described.\r\n\r\nMyoglobin rises quickly but lacks cardiac specificity. Creatine Kinase-MB (CK-MB) levels rise 4-6 hours post-MI, peak at 24 hours, and return to normal by 72 hours, and are particularly useful for detecting reinfarction. Lactic dehydrogenase (LDH) peaks later and stays elevated longer, which is less useful for early detection.","reference":"Sattar, Husain A. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com, 2019: 74.","responses":[{"text":"Creatine Kinase-MB","correct":false,"visible":false},{"text":"Pyruvate kinase","correct":false,"visible":false},{"text":"Lactic dehydrogenase","correct":false,"visible":false},{"text":"Troponin I","correct":true,"visible":false},{"text":"Myoglobin","correct":false,"visible":false}]},{"id":15556,"text":"In which of the following phases of the cardiac muscle action potential, potassium ions permeability is the highest?","explanation":"In the cardiac muscle action potential, **phase 3** is where potassium ion (K⁺) permeability is the highest. Phase 3 is known as the repolarization phase. During this phase, there is a rapid outflow of K⁺ from the cardiac muscle cells, which is facilitated by the opening of voltage-gated K⁺ channels. This outflow of K⁺ ions results in the return of the membrane potential to its resting level, effectively ending the action potential. This phase is crucial for restoring the electrical conditions of the cell membrane to prepare for the next action potential.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 115.","responses":[{"text":"2","correct":false,"visible":false},{"text":"3","correct":true,"visible":false},{"text":"4","correct":false,"visible":false},{"text":"0","correct":false,"visible":false},{"text":"1","correct":false,"visible":false}]},{"id":15557,"text":"A stab wound in the right intercostal space is most likely to injure which one of the following structures?","explanation":"A stab wound in the right intercostal space is most likely to injure the **Right atrium**. The right atrium is located on the right side of the heart and extends slightly to the right of the sternum. Given its anterior and right-sided location in the thoracic cavity, it is positioned in a manner that makes it vulnerable to injury from a stab wound in the right intercostal space.\r\n\r\nThe pulmonary artery is more centrally and superiorly positioned, shielded by the sternum and other heart structures. The right ventricle is located more anteriorly but towards the left side, making it less likely to be injured from a right-sided stab wound. The apex of the heart is positioned more to the left and inferior, beneath the left fifth intercostal space. The liver is located in the right upper quadrant of the abdomen and, although close, is generally protected by the rib cage in this context.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 239.","responses":[{"text":"Apex of heart","correct":false,"visible":false},{"text":"Right atrium","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Pulmonary artery","correct":false,"visible":false},{"text":"Right ventricle","correct":false,"visible":false}]},{"id":15558,"text":"In which of the following locations is the coronary sinus located?","explanation":"The **coronary sinus** is located in the **coronary sulcus**. The coronary sulcus, also known as the atrioventricular groove, is a groove that encircles the heart, marking the external boundary between the atria and ventricles. The coronary sinus runs within this sulcus on the posterior aspect of the heart. It collects deoxygenated blood from the myocardium via various cardiac veins and then drains this blood into the right atrium.\r\n\r\nThe anterior and posterior interventricular sulci separate the left and right ventricles and contain the respective interventricular arteries. The anterior atrioventricular sulcus is located on the anterior surface of the heart, marking the division between the atria and ventricles but does not contain the coronary sinus. The posterior atrioventricular sulcus is on the posterior aspect of the heart but specifically refers to the groove between the atria and ventricles, distinct from the coronary sulcus.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 193.","responses":[{"text":"Posterior interventricular sulcus","correct":false,"visible":false},{"text":"Coronary sulcus","correct":true,"visible":false},{"text":"Posterior atrioventricular sulcus","correct":false,"visible":false},{"text":"Anterior interventricular sulcus","correct":false,"visible":false},{"text":"Anterior atrioventricular sulcus","correct":false,"visible":false}]},{"id":15559,"text":"Which of the following is a branch of the ascending aorta?","explanation":"The **Coronary arteries** are the branches of the ascending aorta. They arise from the base of the aorta just above the aortic valve and are responsible for supplying blood to the heart muscle. The right and left coronary arteries are the primary arteries in this system. \r\n\r\nPosterior intercostal arteries arise from the descending thoracic aorta. Mediastinal arteries, which supply blood to the mediastinum, also typically arise from the thoracic aorta. Esophageal arteries, supplying the esophagus, have various sources including the thoracic aorta. Pericardial arteries, which supply the pericardium, have multiple origins including branches from the thoracic aorta, coronary arteries, and others.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 202.","responses":[{"text":"Esophageal arteries","correct":false,"visible":false},{"text":"Coronary arteries","correct":true,"visible":false},{"text":"Mediastinal arteries","correct":false,"visible":false},{"text":"Pericardial arteries","correct":false,"visible":false},{"text":"Posterior intercostal arteries","correct":false,"visible":false}]},{"id":15560,"text":"Which of the following gives the correct location of the foramen ovale?","explanation":"The **foramen ovale** is correctly located in the **Interatrial septum**. The foramen ovale is a key feature in fetal circulation, allowing blood to pass from the right atrium to the left atrium, bypassing the non-functioning fetal lungs. \r\n\r\nThe coronary sulcus is a groove that marks the external boundary between the atria and ventricles. The anterior and posterior intraventricular septa refer to parts of the septum that separate the left and right ventricles. The coronary sinus is a large vein on the posterior side of the heart that returns deoxygenated blood from the myocardium to the right atrium.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 197.","responses":[{"text":"Coronary sulcus","correct":false,"visible":false},{"text":"Anterior intraventricular septum","correct":false,"visible":false},{"text":"Posterior intraventricular septum","correct":false,"visible":false},{"text":"Interatrial septum","correct":true,"visible":false},{"text":"Coronary sinus","correct":false,"visible":false}]},{"id":15561,"text":"During fetal development, there is right-to-left shunting of blood from the pulmonary trunk to the aorta. What is the name of the structure responsible for this physiological process?","explanation":"The structure responsible for the right-to-left shunting of blood from the pulmonary trunk to the aorta during fetal development is the **Ductus arteriosus**. This shunt is a normal and essential part of fetal circulation. In the fetal period, the lungs are not yet functional, and the oxygenation of blood occurs through the placenta. The ductus arteriosus allows most of the blood from the right ventricle to bypass the non-functioning fetal lungs and enter the systemic circulation directly.\r\n\r\nThe foramen ovale allows blood to flow from the right atrium to the left atrium, bypassing the lungs. Foramen secundum and foramen primum are related to the development of the foramen ovale. The sinus venosus is an embryological structure contributing to the development of the heart.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 289.","responses":[{"text":"Foramen primum","correct":false,"visible":false},{"text":"Ductus arteriosus","correct":true,"visible":false},{"text":"Sinus venosus","correct":false,"visible":false},{"text":"Foramen secundum","correct":false,"visible":false},{"text":"Foramen ovale","correct":false,"visible":false}]},{"id":15563,"text":"One of the presentations in right-sided heart failure patients, who are chronically bedridden, is anasarca. What does the term anasarca mean?","explanation":"**Anasarca** refers to **Generalized edema**. It is a medical term used to describe severe, widespread accumulation of fluid in the interstitial tissue spaces of the body. This condition is often seen in patients with right-sided heart failure who are chronically bedridden. In right-sided heart failure, the heart fails to pump blood effectively to the lungs, leading to a backlog of blood in the systemic circulation. This backlog increases venous pressure and causes fluid to leak from the capillaries into tissues, leading to generalized edema, or anasarca.\r\n\r\nAscites is the accumulation of fluid in the peritoneal cavity. Left ventricular hypertrophy is the thickening of the walls of the left ventricle of the heart. Renal congestion refers to congestion in the kidneys due to circulatory overload. Pulmonary hypertension is high blood pressure in the blood vessels that supply the lungs.","reference":"Kumar, Vinay, Abul K Abbas, Jon C Aster, Ramzi S Cotran, and Stanley L Robbins. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier, 2020: 530.","responses":[{"text":"Ascites","correct":false,"visible":false},{"text":"Renal congestion","correct":false,"visible":false},{"text":"Left ventricular hypertrophy","correct":false,"visible":false},{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"Generalized edema","correct":true,"visible":false}]},{"id":15583,"text":"Which of the following is a type of shock that results from a spinal injury?","explanation":"The correct answer is **Neurogenic** shock. This type of shock occurs due to a spinal injury. In neurogenic shock, there is a loss of sympathetic tone, which leads to vasodilation and decreased systemic vascular resistance. This results in hypotension and, often, bradycardia. The key feature distinguishing neurogenic shock from other types of shock is the presence of spinal cord injury leading to disruption of sympathetic outflow.\r\n\r\nAnaphylactic shock is caused by a severe allergic reaction. Hypovolemic shock results from significant loss of blood volume. Septic shock is a consequence of severe infection leading to systemic inflammation. Cardiogenic shock occurs due to the failure of the heart's pumping action.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 300.","responses":[{"text":"Anaphylactic","correct":false,"visible":false},{"text":"Cardiogenic","correct":false,"visible":false},{"text":"Septic","correct":false,"visible":false},{"text":"Hypovolemic","correct":false,"visible":false},{"text":"Neurogenic","correct":true,"visible":false}]},{"id":15584,"text":"A 20-year-old male presents to the emergency department with the complaint of an allergic reaction following peanuts consumption. Which of the following is most likely to be observed in this patient?","explanation":"**Anaphylactic shock** is a severe, life-threatening allergic reaction characterized by rapid onset. It is typically triggered by exposure to allergens, such as peanuts in this scenario, leading to the release of histamines and other mediators from mast cells and basophils. This reaction results in vasodilation, increased capillary permeability, and smooth muscle contraction, causing symptoms like hypotension, bronchospasm, and potentially fatal cardiovascular collapse.\r\n\r\nOther types of shock listed, such as cardiogenic, neurogenic, hypovolemic, and septic, are less likely in this scenario. Cardiogenic shock occurs due to heart failure, neurogenic shock is due to spinal cord injury or CNS damage, hypovolemic shock results from significant blood or fluid loss, and septic shock is caused by severe infection.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 300.","responses":[{"text":"Neurogenic","correct":false,"visible":false},{"text":"Septic","correct":false,"visible":false},{"text":"Cardiogenic","correct":false,"visible":false},{"text":"Hypovolemic","correct":false,"visible":false},{"text":"Anaphylactic","correct":true,"visible":false}]},{"id":15585,"text":"A young patient presented to the emergency department with signs of shock after a bacterial infection. Which of the following types of shock is the most likely to be found in this patient?","explanation":"In this clinical scenario, the most likely type of shock is **Septic Shock**. Septic shock occurs due to a systemic inflammatory response to infection, often bacterial, leading to widespread vasodilation, increased capillary permeability, and decreased systemic vascular resistance. These changes result in hypotension and impaired tissue perfusion despite adequate intravascular volume, defining characteristics of septic shock.\r\n\r\n- **Cardiogenic shock** is caused by heart failure, which does not directly relate to bacterial infection.\r\n- **Anaphylactic shock** is a severe allergic reaction, not primarily due to infection.\r\n- **Neurogenic shock** results from nervous system damage, unrelated to infection.\r\n- **Hypovolemic shock** is due to significant fluid loss, which is not indicated in the patient's presentation.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 300.","responses":[{"text":"Cardiogenic","correct":false,"visible":false},{"text":"Neurogenic","correct":false,"visible":false},{"text":"Anaphylactic","correct":false,"visible":false},{"text":"Hypovolemic","correct":false,"visible":false},{"text":"Septic","correct":true,"visible":false}]},{"id":15612,"text":"A middle-aged patient who underwent cholecystectomy presented to the outpatient department with steatorrhea. Improper absorption of which of the following could be the reason for this condition?","explanation":"In the context of a patient with steatorrhea post-cholecystectomy, improper absorption of **lipids** is the most likely cause. Cholecystectomy, the surgical removal of the gallbladder, impacts bile storage and release. Bile is crucial for emulsifying fats in the diet, facilitating their digestion and absorption. Without adequate bile release, as can occur post-cholecystectomy, fat malabsorption results, leading to steatorrhea, characterized by fatty, malodorous stools.\r\n\r\nOther options like carbohydrates, proteins, vitamins, and iron have different absorption mechanisms and are less likely to be directly affected by cholecystectomy. Carbohydrates and proteins are primarily digested and absorbed in the small intestine through enzymes from the pancreas and intestinal lining. While certain vitamins (A, D, E, K) are fat-soluble and could be malabsorbed due to lipid malabsorption, their deficiency alone is less likely to cause steatorrhea. Iron absorption, primarily in the duodenum, is also not directly affected by cholecystectomy.","reference":"Ferrier, Denise R. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Lippincott Illustrated Reviews. Philadelphia: Wolters Kluwer, 2020: 177.","responses":[{"text":"Carbohydrates","correct":false,"visible":false},{"text":"Proteins","correct":false,"visible":false},{"text":"Lipids","correct":true,"visible":false},{"text":"Vitamins","correct":false,"visible":false},{"text":"Iron","correct":false,"visible":false}]},{"id":15613,"text":"Which type of shock is characteristically found in patients with peritonitis having warm extremities?","explanation":"In patients with peritonitis, **septic shock** is the most characteristic type of shock. Septic shock is a severe and potentially fatal condition that occurs due to a systemic response to infection, in this case, peritonitis. It is marked by vasodilation, increased capillary permeability, and decreased systemic vascular resistance, leading to a drop in blood pressure. Despite the low blood pressure, patients in the early stage of septic shock may have warm extremities due to the profound vasodilation. This is in contrast to other types of shock like hypovolemic, cardiogenic, or anaphylactic shock, where extremities are usually cool and clammy due to vasoconstriction. Neurogenic shock can also cause vasodilation, but it's typically associated with spinal cord injury or other nervous system damage rather than infection.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 300.","responses":[{"text":"Cardiogenic","correct":false,"visible":false},{"text":"Anaphylactic","correct":false,"visible":false},{"text":"Neurogenic","correct":false,"visible":false},{"text":"Hypovolemic","correct":false,"visible":false},{"text":"Septic","correct":true,"visible":false}]},{"id":15615,"text":"During coronary angiography, a male patient was found to have a blockage of the branch of a coronary artery. However, the patient did not develop any symptoms of myocardial infarction. What could be the possible reason for this?","explanation":"In cases where a coronary artery blockage is present but does not lead to myocardial infarction, **collateral circulation** is often the contributing factor. Collateral circulation involves the development of small, new blood vessels that form a natural bypass over blocked or narrowed arteries. This process allows blood to flow around the blocked area, thereby ensuring a supply of oxygen and nutrients to the myocardial tissue. Collateral circulation can develop over time in response to gradual narrowing of coronary arteries, which might explain the absence of myocardial infarction symptoms in the patient despite having a blockage.\r\n\r\nThrombolysis refers to the dissolution of a clot, while bilateral circulation is not a recognized term in this context. Increased compliance of the blocked artery or vasodilation would not sufficiently compensate for a significant blockage in a coronary artery.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 212-213.","responses":[{"text":"Vasodilation of the blocked artery","correct":false,"visible":false},{"text":"Increased compliance of the blocked artery","correct":false,"visible":false},{"text":"Bilateral circulation","correct":false,"visible":false},{"text":"Thrombolysis","correct":false,"visible":false},{"text":"Collateral circulation","correct":true,"visible":false}]},{"id":15617,"text":"Normally, when the pressure blocking the blood vessels is released, there is a greater blood flow to the tissues. What is this phenomenon called?","explanation":"Reactive hyperemia is a process where, after a temporary blockage of blood flow, there is a marked increase in blood flow to a tissue once the blockage is released. This phenomenon occurs as a response to the accumulation of metabolic byproducts and a decrease in oxygen levels in the tissues during the period of ischemia (lack of blood flow). When the obstruction is removed, the blood vessels dilate significantly, allowing an increased blood flow to replenish oxygen and remove accumulated metabolites, leading to a temporary state of hyperemia (increased blood flow). This response is a protective mechanism to compensate for the period of oxygen deprivation and helps in preventing tissue damage.\r\n\r\nActive hyperemia, on the other hand, is an increase in blood flow associated with increased tissue activity. Hypovolemic shock refers to a state of diminished blood volume, and angiogenesis is the formation of new blood vessels.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 208.","responses":[{"text":"Hypovolemic shock","correct":false,"visible":false},{"text":"Angiogenesis","correct":false,"visible":false},{"text":"Active hyperemia","correct":false,"visible":false},{"text":"Reactive hyperemia","correct":true,"visible":false},{"text":"Tissue vascularity","correct":false,"visible":false}]},{"id":15621,"text":"Which of the following occurs immediately after the QRS complex?","explanation":"Following the QRS complex on an electrocardiogram (ECG), which signifies ventricular depolarization, the next significant event is **ventricular repolarization**. This phase is represented by the T wave on the ECG. Ventricular repolarization is critical as it signifies the recovery of the ventricular muscle cells in preparation for the next cardiac cycle. \r\n\r\nWhile the QRS complex indicates that the ventricles are depolarized and contracting (ventricular systole), repolarization is the process by which the heart muscle cells return to their resting state. It is important to note that atrial repolarization also occurs concurrently with ventricular depolarization, but it is typically not visible on the ECG because it is overshadowed by the larger electrical activity of the ventricles.\r\n\r\nIsovolumic contraction occurs just after the QRS complex, but before ventricular ejection; however, it is not represented as a distinct waveform on the ECG.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 118.","responses":[{"text":"Atrial systole","correct":false,"visible":false},{"text":"Isovolumic contraction","correct":false,"visible":false},{"text":"Atrial repolarization","correct":false,"visible":false},{"text":"Ventricular systole","correct":false,"visible":false},{"text":"Ventricular repolarization","correct":true,"visible":false}]},{"id":15622,"text":"In which of the blood vessels are pinocytotic vesicles seen?","explanation":"**Continuous capillaries** have a continuous endothelial lining with tight junctions between the endothelial cells. While they do not have large gaps or fenestrations like some other capillary types, continuous capillaries can perform **pinocytosis**, a process in which cells engulf fluids and solutes from the bloodstream by forming pinocytotic vesicles. This allows for the selective transport of molecules across the capillary wall.\r\n\r\n***\r\n\r\nFenestrated capillaries have small pores or fenestrations in their endothelial cells, making them more permeable to fluids and solutes than continuous capillaries.\r\n\r\nDiscontinuous capillaries, also known as sinusoids, are irregularly shaped endothelial cells with large gaps between them. These gaps allow for the passage of larger molecules and even cells.\r\n\r\nThe aorta is a large artery with a thick, muscular wall and does not have the same type of endothelial characteristics or permeability as capillaries, so pinocytotic vesicles are not typically found in the aorta.","reference":"Mescher, Anthony L. Junqueira’s Basic Histology: Text and Atlas. 15th ed. New York, NY: McGraw-Hill Medical, 2018: 226.","responses":[{"text":"Sinusoids","correct":false,"visible":false},{"text":"Continuous capillaries","correct":true,"visible":false},{"text":"Aorta","correct":false,"visible":false},{"text":"Fenestrated capillaries","correct":false,"visible":false},{"text":"Discontinuous capillaries","correct":false,"visible":false}]},{"id":15623,"text":"A 50-year-old patient presented to the emergency department with a myocardial infarction of the inferior wall of the left ventricle. Which of the following arteries is most likely to be damaged?","explanation":"In the case of a myocardial infarction (MI) of the inferior wall of the left ventricle, the most likely affected artery is the **right coronary artery (RCA)**. The RCA typically supplies blood to the right atrium, right ventricle, and often the inferior portion of the left ventricle, particularly the inferior wall and part of the interventricular septum. \r\n\r\nThe left circumflex coronary artery mainly supplies the lateral and posterior walls of the left ventricle and the left atrium. The left anterior descending coronary artery (LAD) supplies the front and bottom of the left ventricle and the front of the interventricular septum. The pulmonary artery and aorta are not directly involved in supplying blood to the myocardium.\r\n\r\nTherefore, in an inferior wall MI, the RCA is most commonly implicated.","reference":"Kumar, Vinay, Abul K Abbas, Jon C Aster, Ramzi S Cotran, and Stanley L Robbins. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier, 2020: 544.","responses":[{"text":"Left circumflex coronary artery","correct":false,"visible":false},{"text":"Left anterior descending coronary artery","correct":false,"visible":false},{"text":"Right coronary artery","correct":true,"visible":false},{"text":"Aorta","correct":false,"visible":false},{"text":"Pulmonary artery","correct":false,"visible":false}]},{"id":15624,"text":"Which of the following provides an afferent blood supply to the right atrium?","explanation":"The **superior vena cava** is the major vein that carries deoxygenated blood from the upper half of the body to the right atrium of the heart. It is one of the two main veins (the other being the inferior vena cava) that bring deoxygenated blood back to the heart from systemic circulation. The superior vena cava collects blood from the head, neck, upper limbs, and upper thorax and delivers it to the right atrium. \r\n\r\nThe aorta, on the other hand, is an artery that carries oxygenated blood from the left ventricle to the body. Pulmonary arteries carry deoxygenated blood from the right ventricle to the lungs. The coronary arteries supply blood to the heart muscle itself. Pulmonary veins carry oxygenated blood from the lungs to the left atrium.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 196.","responses":[{"text":"Aorta","correct":false,"visible":false},{"text":"Coronary arteries","correct":false,"visible":false},{"text":"Pulmonary veins","correct":false,"visible":false},{"text":"Pulmonary arteries","correct":false,"visible":false},{"text":"Superior vena cava","correct":true,"visible":false}]},{"id":15625,"text":"Which of the following structures does the left atrium open into?","explanation":"The left atrium is one of the four chambers of the heart, primarily receiving oxygenated blood from the lungs via the pulmonary veins. The primary function of the left atrium is to act as a holding chamber for blood returning from the lungs and to act as a pump to transport blood to other areas of the heart. The left atrium opens into the **left ventricle** through the mitral valve (also known as the bicuspid valve). \r\n\r\nWhen the left atrium contracts, it forces blood through the mitral valve into the left ventricle. The left ventricle then contracts to pump oxygen-rich blood into the systemic circulation via the aorta.","reference":"Drake, Richard L. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier, 2020: 196.","responses":[{"text":"Right atrium","correct":false,"visible":false},{"text":"Right ventricle","correct":false,"visible":false},{"text":"Pulmonary arteries","correct":false,"visible":false},{"text":"Left ventricle","correct":true,"visible":false},{"text":"Pulmonary veins","correct":false,"visible":false}]},{"id":15626,"text":"What is the correct sequence of the conduction of cardiac impulses in the heart?","explanation":"The cardiac conduction system controls the heart rate and coordinates the contraction of cardiac muscle. The correct sequence of conduction of cardiac impulses in the heart is:\r\n\r\n1. **Sinoatrial (SA) node:** Located in the right atrium, it is the natural pacemaker of the heart. The impulse starts here.\r\n   \r\n2. **Atrioventricular (AV) node:** The impulse travels from the SA node to the AV node, which is located at the lower end of the right atrium near the septum.\r\n\r\n3. **Bundle of His:** After the AV node, the impulse travels down the bundle of His, a collection of heart muscle cells specialized for electrical conduction. It transmits the electrical impulses from the AV node to the point of the split into left and right bundle branches.\r\n\r\n4. **Left and right bundle branches:** These pathways conduct the impulses down the left and right sides of the interventricular septum.\r\n\r\n5. **Purkinje fibers:** The final part of the conduction system, these fibers spread throughout the ventricular myocardium, causing the muscle to contract in a coordinated manner.\r\n\r\nThis sequence ensures that the atria contract slightly before the ventricles, allowing for efficient blood flow from the atria to the ventricles.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 128-131.","responses":[{"text":"SA node → AV node → bundle of His → left and right bundle branches → Purkinje fibers","correct":true,"visible":false},{"text":"SA node → bundle of His → Purkinje fibers → AV node → left and right bundle branches","correct":false,"visible":false},{"text":"SA node → AV node → Purkinje fibers → bundle of His → left and right bundle branches","correct":false,"visible":false},{"text":"SA node → bundle of His → AV node → Purkinje fibers → left and right bundle branches","correct":false,"visible":false},{"text":"SA node → Purkinje fibers → AV node → bundle of His → left and right bundle branches","correct":false,"visible":false}]},{"id":15627,"text":"In paroxysmal atrial tachycardia, inverted p wave is observed in which of the following leads?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 162-163.","responses":[{"text":"I","correct":true,"visible":false},{"text":"II","correct":false,"visible":false},{"text":"aVR","correct":false,"visible":false},{"text":"III","correct":false,"visible":false},{"text":"aVF","correct":false,"visible":false}]},{"id":15628,"text":"A medical student is given an ECG in which lead I and III potentials are 0.5 mv and 0.7 mv, respectively. Taking these values into account, what is the potential of lead II?","explanation":"The correct answer is **1.2 mv**.\r\nIn electrocardiography (ECG), the potential of lead II is calculated based on Einthoven's triangle, which illustrates the relationships between the limb leads (I, II, III). According to Einthoven's law, the sum of the potentials in leads I and III equals the potential in lead II (Lead II = Lead I + Lead III).\r\n\r\nGiven:\r\n- Lead I = 0.5 mv\r\n- Lead III = 0.7 mv\r\n\r\nApplying Einthoven's law:\r\nLead II = 0.5 mv (Lead I) + 0.7 mv (Lead III) = 1.2 mv.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 139.","responses":[{"text":"1.2 mv","correct":true,"visible":false},{"text":"0 mv","correct":false,"visible":false},{"text":"-0.2 mv","correct":false,"visible":false},{"text":"-1.2 mv","correct":false,"visible":false},{"text":"0.2 mv","correct":false,"visible":false}]}
]

